    return NextResponse.json({ error: 'Duplicate' }, { status: 409 })
  }
  const hash = await bcrypt.hash(name, 10)
  const result = await db.query('INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id', [hash, normalized])
  await sendWelcomeEmail(normalized)
